class Codec:
    def encode(self, strs: list[str]) -> str:
        res = []
        for s in strs:
            res.append(f"{len(s)}:{s}")
        return "".join(res)

    def decode(self, s: str) -> list[str]:
        res = []
        i = 0
        while i < len(s):
            colon = s.find(":", i)
            length = int(s[i:colon])
            res.append(s[colon + 1 : colon + 1 + length])
            i = colon + 1 + length
        return res

