def radixSort(nums: list[int]) -> list[int]:
    if not nums:
        return nums
    max_val = max(nums)
    exp = 1
    while max_val // exp > 0:
        buckets = [[] for _ in range(10)]
        for x in nums:
            digit = (x // exp) % 10
            buckets[digit].append(x)
        nums = []
        for b in buckets:
            nums.extend(b)
        exp *= 10
    return nums

