class LFUCache:
    def __init__(self, capacity: int):
        from collections import defaultdict, OrderedDict
        self.capacity = capacity
        self.vals = {}
        self.counts = {}
        self.lists = defaultdict(OrderedDict)
        self.min_freq = 0

    def get(self, key: int) -> int:
        if key not in self.vals:
            return -1
        count = self.counts[key]
        self.counts[key] = count + 1
        self.lists[count].pop(key)
        if not self.lists[count] and count == self.min_freq:
            self.min_freq += 1
        self.lists[count + 1][key] = self.vals[key]
        return self.vals[key]

    def put(self, key: int, value: int) -> None:
        if self.capacity <= 0:
            return
        if key in self.vals:
            self.vals[key] = value
            self.get(key)
            return
        if len(self.vals) >= self.capacity:
            evict_key, _ = self.lists[self.min_freq].popitem(last=False)
            del self.vals[evict_key]
            del self.counts[evict_key]
        self.vals[key] = value
        self.counts[key] = 1
        self.lists[1][key] = value
        self.min_freq = 1

