def canReach(s: str, minJump: int, maxJump: int) -> bool:
    n = len(s)
    if s[n-1] == '1':
        return False
    dp = [False] * n
    dp[0] = True
    pre = 0
    for i in range(1, n):
        if i >= minJump:
            pre += dp[i - minJump]
        if i > maxJump:
