class Elevator:
    def __init__(self):
        self.current_floor = 0
        self.direction = 0
        self.requests = set()

    def addRequest(self, floor: int) -> None:
        self.requests.add(floor)

    def step(self) -> int:
        if self.current_floor in self.requests:
            self.requests.remove(self.current_floor)
        if not self.requests:
            self.direction = 0
        else:
            if self.direction == 0:
                if any(r > self.current_floor for r in self.requests):
                    self.direction = 1
                elif any(r < self.current_floor for r in self.requests):
                    self.direction = -1
            elif self.direction == 1:
                if not any(r >= self.current_floor for r in self.requests):
                    if any(r < self.current_floor for r in self.requests):
                        self.direction = -1
                    else:
                        self.direction = 0
            elif self.direction == -1:
                if not any(r <= self.current_floor for r in self.requests):
                    if any(r > self.current_floor for r in self.requests):
                        self.direction = 1
                    else:
                        self.direction = 0
        if self.direction != 0:
            self.current_floor += self.direction
            if self.current_floor in self.requests:
                self.requests.remove(self.current_floor)
        return self.current_floor

