        self.root = None

    def insert(self, val: int) -> None:
        new_node = TreeNode(val)
        if not self.root:
            self.root = new_node
            return
        from collections import deque
        q = deque([self.root])
        while q:
            node = q.popleft()
            if not node.left:
                node.left = new_node
                return
            else:
                q.append(node.left)
            if not node.right:
                node.right = new_node
                return
            else:
                q.append(node.right)

