    n = len(ranks)
    tree = [0] * (n + 1)
    def add(i, delta):
        while i <= n:
            tree[i] += delta
            i += i & (-i)
    def query(i):
        s = 0
        while i > 0:
            s += tree[i]
            i -= i & (-i)
        return s
