def findWords(board: list[list[str]], words: list[str]) -> list[str]:
    trie = {}
    for w in words:
        curr = trie
        for c in w:
            if c not in curr:
                curr[c] = {}
            curr = curr[c]
        curr["$"] = w
    m, n = len(board), len(board[0])
    res = []
    def dfs(r, c, node):
        ch = board[r][c]
        if ch not in node:
            return
        next_node = node[ch]
        if "$" in next_node:
            res.append(next_node.pop("$"))
        board[r][c] = "#"
        for nr, nc in ((r + 1, c), (r - 1, c), (r, c + 1), (r, c - 1)):
            if 0 <= nr < m and 0 <= nc < n and board[nr][nc] != "#":
                dfs(nr, nc, next_node)
        board[r][c] = ch
        if not next_node:
            node.pop(ch)
    for r in range(m):
        for c in range(n):
            dfs(r, c, trie)
    return sorted(res)

