class FileSystem:
    class Node:
        def __init__(self):
            self.children = {}
            self.is_file = False
            self.content = ""

    def __init__(self):
        self.root = self.Node()

    def _traverse(self, path: str):
        curr = self.root
        if path == "/":
            return curr
        parts = path.split("/")[1:]
        for p in parts:
            if p not in curr.children:
                return None
            curr = curr.children[p]
        return curr

    def ls(self, path: str) -> list[str]:
        curr = self._traverse(path)
        if curr.is_file:
            return [path.split("/")[-1]]
        return sorted(curr.children.keys())

    def mkdir(self, path: str) -> None:
        curr = self.root
        parts = path.split("/")[1:]
        for p in parts:
            if p not in curr.children:
                curr.children[p] = self.Node()
            curr = curr.children[p]

    def addContentToFile(self, filePath: str, content: str) -> None:
        curr = self.root
        parts = filePath.split("/")[1:]
        for p in parts[:-1]:
            curr = curr.children[p]
        f = parts[-1]
        if f not in curr.children:
            curr.children[f] = self.Node()
        curr = curr.children[f]
        curr.is_file = True
        curr.content += content

    def readContentFromFile(self, filePath: str) -> str:
        curr = self._traverse(filePath)
        return curr.content
